/// Look up a codepoint's atlas cell. `None` if not in the bundled set.
pub fn lookup(codepoint: u32) -> Option<(u16, u16)> {
    EMOJI_TABLE
        .binary_search_by_key(&codepoint, |&(cp, _, _)| cp)
        .ok()
        .map(|i| (EMOJI_TABLE[i].1, EMOJI_TABLE[i].2))
}
